import React from 'react';

const RezumeTemplate = ({ data }) => {
  const { personalInfo, education, experience, projects, skills, sectionTitles, summary, certifications } = data;

  return (
    <div id="resume-template" className="rezume-container">
      {/* Header */}
      <header className="rezume-header">
        <div className="header-top">
          <div className="header-left">
            <h1 className="name">{personalInfo.fullName}</h1>
            <div className="header-links">
              {personalInfo.website && <><a href={`https://${personalInfo.website}`} target="_blank" rel="noreferrer">{personalInfo.website}</a> | </>}
              <a href={`https://${personalInfo.linkedin}`} target="_blank" rel="noreferrer">LinkedIn</a> | 
              <a href={`https://${personalInfo.github}`} target="_blank" rel="noreferrer">GitHub</a> | 
              <a href={`https://${personalInfo.leetcode}`} target="_blank" rel="noreferrer">Leetcode</a>
            </div>
          </div>
          <div className="header-right">
            <div className="contact-item">Location: {personalInfo.location}</div>
            <div className="contact-item">Email: <a href={`mailto:${personalInfo.email}`}>{personalInfo.email}</a> | Mobile: {personalInfo.phone}</div>
          </div>
        </div>

        {personalInfo.role && (
          <div className="role-section">
            <h2 className="role-title">{personalInfo.role.toUpperCase()}</h2>
            <div className="role-line"></div>
          </div>
        )}
      </header>

      {/* Summary */}
      {summary && (
        <section className="section summary-section">
          <p className="summary-text">{summary}</p>
        </section>
      )}

      {/* Skills */}
      <section className="section">
        <h2 className="section-title">{sectionTitles?.skills?.toUpperCase() || 'TECHNICAL SKILLS'}</h2>
        <div className="section-line"></div>
        <div className="skills-grid">
          {skills.map((skill, index) => (
            <div key={index} className="skill-row">
              <span className="skill-label">{skill.title}</span>
              <span className="skill-sep">:</span>
              <span className="skill-details">{skill.details}</span>
            </div>
          ))}
        </div>
      </section>

      {/* Experience */}
      <section className="section">
        <h2 className="section-title">{sectionTitles?.experience?.toUpperCase() || 'EXPERIENCE'}</h2>
        <div className="section-line"></div>
        {experience.map((exp, index) => (
          <div key={index} className="exp-item">
            <div className="exp-header">
              <span className="bold">{exp.role}</span>
              <span className="date">{exp.date}</span>
            </div>
            <div className="exp-sub">
              <span className="italic">{exp.company}</span>
              <span className="italic">{exp.location}</span>
            </div>
            <ul className="bullets">
              {exp.bullets.map((bullet, i) => (
                <li key={i}>{bullet}</li>
              ))}
            </ul>
          </div>
        ))}
      </section>

      {/* Education */}
      <section className="section">
        <h2 className="section-title">{sectionTitles?.education?.toUpperCase() || 'EDUCATION'}</h2>
        <div className="section-line"></div>
        {education.map((edu, index) => (
          <div key={index} className="edu-item">
            <div className="edu-header">
              <span className="bold">{edu.school}</span>
              <span className="location">{edu.location}</span>
            </div>
            <div className="edu-sub">
              <span className="italic">{edu.degree}</span>
              <span className="date">{edu.date}</span>
            </div>
          </div>
